#include<bits/stdc++.h>
using namespace std;
int n,a[10010],ans[10010];
bool vis[10010];
int s[10010][2],match[10010];
bool dfs(int x)
{
    for(int i=0;i<2;i++)
    {
        int v=s[x][i];
        if(vis[v])
        {
            continue;
        }
        vis[v]=true;
        if(match[v]==0||dfs(match[v]))
        {
            match[v]=x;
            ans[x]=v;
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d",&n);
    for(int i=0;i<n;i++)
    {
        scanf("%d",&a[i]);
        s[i][0]=(i-a[i]+n)%n;
        s[i][1]=(i+a[i])%n;
        if(s[i][0]>s[i][1])
        {
            swap(s[i][0],s[i][1]);
        }
    }
    int ans1=0;
    for(int i=n-1;i>=0;i--)
    {
        memset(vis,0,sizeof(vis));
        ans1+=dfs(i);
    }
    if(ans1!=n)
    {
        printf("No Answer");
    }
    else
    {
        for(int i=0;i<n;i++)
        {
            printf("%d ",ans[i]);
        }
    }
    return 0;
}
